window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["epa-608"] = window.COURSE_LANG["epa-608"] || {};
window.COURSE_LANG["epa-608"]["es"] = [
  {"id":1,"q":"La capa de ozono es importante porque:","opts":["Atrapa el calor cerca del suelo","Produce el oxígeno que respiramos","Crea refrigerante","Protege la Tierra de la radiación ultravioleta (UV) dañina"],"re":"El ozono estratosférico absorbe la radiación ultravioleta (UV) dañina del sol."},
  {"id":2,"q":"¿Qué parte de una molécula de CFC o HCFC destruye el ozono estratosférico?","opts":["Hidrógeno","Flúor","Cloro","Carbono"],"re":"El cloro liberado de los CFC y HCFC destruye catalíticamente las moléculas de ozono."},
  {"id":3,"q":"El acuerdo internacional para eliminar las sustancias que agotan el ozono es:","opts":["La Clean Air Act","El Tratado de Kioto","El Programa SNAP","El Protocolo de Montreal"],"re":"El Protocolo de Montreal es el tratado internacional que elimina las sustancias que agotan el ozono."},
  {"id":4,"q":"Según la Sección 608 de la Clean Air Act, liberar refrigerante a propósito durante el servicio es:","opts":["Permitido en pequeñas cantidades","Permitido solo para HFC","Ilegal","Permitido si se hace al aire libre"],"re":"Liberar refrigerantes CFC, HCFC y sustitutos (HFC) durante el servicio, mantenimiento o desecho es ilegal."},
  {"id":5,"q":"La sigla ODP significa:","opts":["Potencial de Agotamiento del Ozono","Proceso de Difusión de Oxígeno","Presión de Descarga de Ozono","Punto de Distribución Abierto"],"re":"ODP significa Potencial de Agotamiento del Ozono — una medida de cuánto daña una sustancia a la capa de ozono."},
  {"id":6,"q":"¿Qué familia de refrigerantes NO contiene cloro y tiene potencial de agotamiento de ozono cero?","opts":["CFC","HCFC","HFC","Todas contienen cloro"],"re":"Los HFC (p. ej. R-134a, R-410A) no contienen cloro y tienen ODP cero, aunque sí tienen potencial de calentamiento global."},
  {"id":7,"q":"El refrigerante regulado solo puede venderse a:","opts":["Un técnico certificado por la EPA","Un plomero con licencia","Cualquier propietario de vivienda","Cualquier persona mayor de 21"],"re":"Los refrigerantes regulados solo pueden venderse a técnicos certificados bajo la Sección 608 (o 609) de la EPA."},
  {"id":8,"q":"En términos de la EPA, la recuperación (recovery) de refrigerante significa:","opts":["Limpiarlo para reusarlo en el sitio","Procesarlo a especificaciones de producto nuevo","Liberarlo de forma segura al aire libre","Sacarlo del sistema y guardarlo en un contenedor externo"],"re":"Recuperar significa sacar el refrigerante de un sistema y guardarlo en un contenedor externo, sin probarlo ni procesarlo."},
  {"id":9,"q":"El refrigerante reclamado (reclaimed) ha sido:","opts":["Solo recuperado en un cilindro","Limpiado en el sitio con un filtro","Reprocesado para cumplir el estándar de pureza de producto nuevo (AHRI 700)","Liberado tras la recuperación"],"re":"El refrigerante reclamado se reprocesa al estándar de pureza AHRI 700, normalmente por un reclamador certificado."},
  {"id":10,"q":"El R-22 pertenece a qué familia de refrigerantes?","opts":["HCFC","CFC","HFC","Refrigerante natural"],"re":"El R-22 es un HCFC; su producción e importación se eliminaron a partir del 1 de enero de 2020."},
  {"id":11,"q":"Un cilindro de refrigerante desechable (de un solo uso) nunca debe ser:","opts":["Reciclado cuando está vacío","Usado para recuperar","Almacenado de pie","Rellenado"],"re":"Los cilindros desechables nunca deben rellenarse; rellenarlos es peligroso e ilegal."},
  {"id":12,"q":"Los registros de servicio y certificación de la Sección 608 deben conservarse por lo menos:","opts":["6 meses","1 año","3 años","10 años"],"re":"Los registros de servicio y certificación de refrigerante deben conservarse al menos 3 años."},
  {"id":13,"q":"El programa de la EPA que revisa y lista los refrigerantes sustitutos aceptables es:","opts":["SNAP","OSHA","AHRI","DOT"],"re":"SNAP (Significant New Alternatives Policy) revisa y lista los refrigerantes sustitutos aceptables."},
  {"id":14,"q":"Un cilindro de recuperación nunca debe llenarse por encima de qué porcentaje de su capacidad?","opts":["50%","80%","95%","100%"],"re":"Nunca llenes un cilindro de recuperación por encima del 80% para dejar espacio a la expansión del líquido y evitar una ruptura hidrostática."},
  {"id":15,"q":"Un cilindro de recuperación reutilizable (rellenable, DOT) debe recalificarse o probarse hidrostáticamente cada:","opts":["1 año","5 años","10 años","Nunca necesita prueba"],"re":"Los cilindros rellenables DOT deben recalificarse (por ejemplo, con prueba hidrostática) cada 5 años."},
  {"id":16,"q":"Un cilindro de recuperación de refrigerante se identifica por qué esquema de color?","opts":["Todo verde","Cuerpo azul con tapa blanca","Todo rojo","Cuerpo gris con tapa amarilla"],"re":"Los cilindros de recuperación se identifican por un cuerpo gris con el hombro o tapa amarilla."},
  {"id":17,"q":"El refrigerante líquido sobre la piel puede causar:","opts":["Congelación (quemadura por frío)","Un leve calentamiento","Quemadura de sol","Ningún efecto"],"re":"El refrigerante líquido puede causar congelación; usa siempre guantes y protección ocular."},
  {"id":18,"q":"Los distintos refrigerantes nunca deben ser:","opts":["Recuperados","Almacenados de pie","Pesados antes de cargar","Mezclados en un mismo cilindro"],"re":"Mezclar refrigerantes los vuelve inservibles e imposibles de reclamar; mantén cada tipo por separado."},
  {"id":19,"q":"Para probar fugas con presión debes usar:","opts":["Oxígeno puro","Aire comprimido de taller","Nitrógeno seco (con una traza de refrigerante donde se permita)","Acetileno"],"re":"Usa nitrógeno seco para las pruebas de presión; nunca oxígeno ni aire de taller."},
  {"id":20,"q":"Por qué nunca debes probar la presión con oxígeno?","opts":["Puede reaccionar con el aceite del compresor y explotar","Es demasiado caro","Corroe la tubería de cobre","Es ilegal comprarlo"],"re":"El oxígeno puede reaccionar de forma explosiva con el aceite del compresor bajo presión; usa nitrógeno seco."},
  {"id":21,"q":"Un electrodoméstico pequeño (small appliance) está sellado de fábrica y cargado con no más de:","opts":["2 libras","5 libras","20 libras","50 libras"],"re":"Un small appliance contiene 5 libras o menos de refrigerante y está sellado herméticamente y cargado de fábrica."},
  {"id":22,"q":"¿Cuál de estos es un small appliance?","opts":["Una unidad de techo de 10 toneladas","Un enfriador centrífugo (chiller)","Un sistema de rack de supermercado","Un refrigerador doméstico"],"re":"Los refrigeradores domésticos, los aires de ventana, los deshumidificadores y los enfriadores de agua son small appliances."},
  {"id":23,"q":"Un equipo de recuperación fabricado después del 15 de nov de 1993, usado en un small appliance con el compresor FUNCIONANDO, debe recuperar al menos:","opts":["80%","85%","90%","95%"],"re":"Con el compresor funcionando, el equipo posterior a 1993 debe retirar el 90% del refrigerante."},
  {"id":24,"q":"Si el compresor del small appliance NO funciona, el equipo posterior a 1993 debe recuperar al menos:","opts":["50%","70%","80%","90%"],"re":"Cuando el compresor no funciona, el requisito baja al 80% de recuperación."},
  {"id":25,"q":"Como alternativa a un porcentaje de recuperación, puedes evacuar un small appliance hasta:","opts":["0 PSIG","4 pulgadas de mercurio (Hg) de vacío","15 PSIG","25 pulgadas de Hg de vacío"],"re":"Recuperar hasta 4 pulgadas de mercurio de vacío cumple el requisito sin importar el porcentaje."},
  {"id":26,"q":"La recuperación dependiente del sistema (pasiva) significa:","opts":["Usar equipo de recuperación autónomo","Usar el propio compresor y la presión del aparato para ayudar a expulsar el refrigerante","Liberar a la atmósfera","Usar solo una bomba de vacío"],"re":"La recuperación pasiva (dependiente del sistema) se apoya en el propio compresor y la presión interna del aparato."},
  {"id":27,"q":"El equipo de recuperación dependiente del sistema solo puede usarse en:","opts":["Small appliances (5 lb o menos)","Aparatos de hasta 50 lb","Aparatos de hasta 200 lb","Cualquier tamaño de aparato"],"re":"La recuperación dependiente del sistema se limita a small appliances de 5 lb o menos."},
  {"id":28,"q":"Para acelerar la recuperación de un small appliance puedes:","opts":["Calentar el compresor con llama abierta","Agregar agua al sistema","Hacer funcionar el compresor en vacío profundo","Calentar y golpear suavemente el compresor, recuperando por ambos lados"],"re":"Recuperar por ambos puntos de acceso y calentar suavemente el compresor acelera la recuperación; nunca uses llama abierta."},
  {"id":29,"q":"En un small appliance que no funciona, una gran cantidad de refrigerante suele quedar en:","opts":["El serpentín del evaporador","El aceite del compresor","El ventilador del condensador","El filtro secador"],"re":"Gran parte del refrigerante atrapado queda disuelto en el aceite del compresor, por eso la recuperación puede ser lenta."},
  {"id":30,"q":"En un small appliance cuyo compresor no funciona, normalmente recuperas accediendo a:","opts":["Solo el lado de baja","Tanto el lado de alta como el de baja","Solo el lado de alta","El panel eléctrico"],"re":"Con el compresor muerto, acceder por ambos lados permite que el refrigerante salga de todo el sistema."},
  {"id":31,"q":"La certificación Tipo II cubre aparatos que usan:","opts":["Refrigerantes de alta presión como R-22 y R-410A","Refrigerantes de baja presión como R-123","Solo small appliances sellados","Aire acondicionado de vehículos"],"re":"El Tipo II cubre aparatos de alta presión que usan refrigerantes como R-22, R-410A y R-502."},
  {"id":32,"q":"¿Cuál de estos es un refrigerante de alta presión?","opts":["R-11","R-123","R-410A","R-113"],"re":"El R-410A es de alta presión; el R-11, R-113 y R-123 son de baja presión."},
  {"id":33,"q":"Para un aparato de alta presión con MENOS de 200 lb, el equipo posterior a 1993 debe alcanzar:","opts":["0 pulgadas de Hg","4 pulgadas de Hg de vacío","10 pulgadas de Hg de vacío","25 pulgadas de Hg de vacío"],"re":"Para aparatos de alta presión de menos de 200 lb con equipo posterior a 1993, recupera hasta 10 pulgadas de mercurio de vacío."},
  {"id":34,"q":"Para un aparato de alta presión de 200 lb O MÁS, el equipo posterior a 1993 debe alcanzar:","opts":["4 pulgadas de Hg de vacío","10 pulgadas de Hg de vacío","15 pulgadas de Hg de vacío","20 pulgadas de Hg de vacío"],"re":"Para aparatos de 200 lb o más, el requisito es 15 pulgadas de mercurio de vacío."},
  {"id":35,"q":"Un servicio mayor que exige recuperación más estricta normalmente significa reemplazar:","opts":["El termostato","El filtro de aire","Un fusible quemado","El compresor, condensador, evaporador o intercambiador de calor auxiliar"],"re":"Reemplazar componentes mayores como el compresor o un intercambiador de calor es servicio mayor con reglas de recuperación más estrictas."},
  {"id":36,"q":"Tras reparar una fuga y evacuar, debes:","opts":["Recargar de inmediato","Verificar que el sistema mantenga el vacío requerido antes de recargar","Ventilar las líneas para limpiarlas","Agregar aceite de compresor extra"],"re":"Confirma que el sistema mantenga el vacío requerido (sin fugas) antes de recargar."},
  {"id":37,"q":"El vacío profundo durante la evacuación se mide con:","opts":["Una mirilla (sight glass)","Un medidor de micrones (vacío)","Un termómetro de sobrecalentamiento","Un manómetro de alta presión estándar"],"re":"Un medidor de micrones mide los niveles de vacío profundo necesarios para una evacuación adecuada."},
  {"id":38,"q":"Los gases no condensables como el aire atrapados en un sistema de alta presión:","opts":["Mejoran la eficiencia","Bajan la temperatura de condensación","No tienen efecto real","Suben la presión de alta y reducen el rendimiento"],"re":"Los no condensables suben la presión de alta y reducen capacidad y eficiencia; evácualos."},
  {"id":39,"q":"En aparatos de 50 lb o más, la fuga de un sistema de confort (comfort cooling) generalmente debe repararse cuando la tasa anual de fuga supera:","opts":["5%","10%","35%","50%"],"re":"Según las reglas actuales, los aparatos de confort (50 lb o más) deben repararse cuando la tasa anual de fuga supera el 10%."},
  {"id":40,"q":"Una fuga de refrigerante se localiza mejor usando:","opts":["Un detector electrónico de fugas u otro método aprobado","Una llama abierta cerca de la junta","El olfato","Solo escuchar el silbido"],"re":"Los detectores electrónicos, las burbujas de jabón o el tinte fluorescente son métodos fiables; nunca uses una llama."},
  {"id":41,"q":"La certificación Tipo III cubre aparatos que usan:","opts":["Refrigerantes de alta presión como R-410A","Refrigerantes de baja presión como R-11, R-113 y R-123","Small appliances sellados","Aire acondicionado de vehículos"],"re":"El Tipo III cubre aparatos de baja presión que usan refrigerantes como R-11, R-113 y R-123."},
  {"id":42,"q":"Los sistemas de baja presión normalmente operan:","opts":["A muy alta presión","Exactamente a presión atmosférica","Por encima de 200 PSIG","En vacío parcial, por debajo de la presión atmosférica"],"re":"Los refrigerantes de baja presión hierven a temperaturas más altas, así que estos sistemas funcionan en vacío."},
  {"id":43,"q":"Con equipo posterior a 1993, un aparato de baja presión debe recuperarse hasta:","opts":["10 pulgadas de Hg","15 pulgadas de Hg","25 mm Hg absolutos","0 PSIG"],"re":"El equipo posterior a 1993 debe recuperar un aparato de baja presión hasta 25 mm Hg absolutos."},
  {"id":44,"q":"El disco de ruptura de un enfriador de baja presión normalmente alivia alrededor de:","opts":["5 PSIG","15 PSIG","50 PSIG","150 PSIG"],"re":"Los sistemas de baja presión usan un disco de ruptura ajustado cerca de 15 PSIG para evitar la sobrepresión."},
  {"id":45,"q":"Al probar la presión de un sistema de baja presión NO debes exceder unos:","opts":["10 PSIG","50 PSIG","100 PSIG","200 PSIG"],"re":"Mantén la presión de prueba baja (alrededor de 10 PSIG) para no reventar el disco de ruptura."},
  {"id":46,"q":"El dispositivo que retira aire y otros no condensables de un enfriador de baja presión es:","opts":["La unidad de purga (purge unit)","El compresor","La válvula de expansión","El filtro secador"],"re":"Una unidad de purga retira los gases no condensables (sobre todo aire) que se acumulan en los sistemas de baja presión."},
  {"id":47,"q":"Para subir la presión del refrigerante y acelerar la recuperación de un enfriador de baja presión, puedes:","opts":["Agregar nitrógeno a 50 PSIG","Presurizar con oxígeno","Abrir el sistema al aire","Calentar suavemente el refrigerante con el calentador de la unidad de recuperación"],"re":"Calentar el refrigerante sube su presión y acelera la recuperación; nunca presurices con aire ni oxígeno."},
  {"id":48,"q":"El exceso de aire y humedad en un sistema de baja presión tiende a:","opts":["Mejorar la eficiencia","Subir la presión y favorecer la formación de ácido y fugas","Bajar el consumo de energía","No tener efecto"],"re":"El aire con humedad sube la presión y favorece la formación de ácido y fugas; purgalo."},
  {"id":49,"q":"El R-123 se clasifica como:","opts":["Un HCFC de baja presión","Un HFC de alta presión","Un CFC","Un refrigerante natural"],"re":"El R-123 es un HCFC de baja presión usado en muchos enfriadores centrífugos."},
  {"id":50,"q":"Como un sistema de baja presión funciona en vacío, cualquier fuga tiende a:","opts":["Dejar escapar el refrigerante rápidamente","No tener efecto real","Aumentar la eficiencia","Atraer aire y humedad HACIA el sistema"],"re":"En vacío, una fuga atrae aire y humedad hacia el sistema en lugar de dejar salir refrigerante."}
];
